import React from 'react';
import { Outlet, Link, Navigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext'; // Lấy dữ liệu mới nhất

const Icons = {
  Home: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#666"} strokeWidth="2"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6" /></svg>,
  Task: ({active}) => <svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke={active?"#003366":"#666"} strokeWidth="2"><path d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2" /></svg>
};

const StaffLayout = () => {
  const { user, logout } = useAuth();
  const { staffList } = useData();
  const location = useLocation();

  if (!user) return <Navigate to="/" />;

  // Lấy thông tin real-time của user hiện tại từ staffList để cập nhật Vị trí/UBI ngay lập tức
  const currentUserInfo = staffList.find(s => s.id === user.id) || user;

  const isActive = (path) => location.pathname === path;
  const linkStyle = (path) => ({
    display: 'flex', flexDirection: 'column', alignItems: 'center', textDecoration: 'none',
    color: isActive(path) ? '#003366' : '#999', fontSize: '0.75rem', fontWeight: isActive(path)?'bold':'normal'
  });

  return (
    <div style={{ display: 'flex', flexDirection: 'column', minHeight: '100vh', background: '#f0f2f5' }}>
      
      {/* Staff Header - Hiển thị thông tin Role & UBI */}
      <header style={{ background: '#fff', padding: '15px', borderBottom: '1px solid #ddd' }}>
         <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <div>
                <h2 style={{ margin: 0, color: '#003366', fontSize: '1.2rem' }}>Chào, {currentUserInfo.name}</h2>
                
                {/* Hiển thị Roles */}
                <div style={{ display: 'flex', gap: '5px', marginTop: '5px', flexWrap: 'wrap' }}>
                    {currentUserInfo.positions && currentUserInfo.positions.length > 0 ? (
                        currentUserInfo.positions.map(p => (
                            <span key={p} style={{ background: '#003366', color: 'white', padding: '2px 6px', borderRadius: '3px', fontSize: '0.7rem' }}>{p}</span>
                        ))
                    ) : <span style={{fontSize: '0.7rem', color: '#888'}}>Chưa xếp vị trí</span>}
                </div>
            </div>
            <button onClick={logout} style={{ border: '1px solid #ddd', background: 'transparent', padding: '5px 10px', borderRadius: '4px' }}>Đăng xuất</button>
         </div>

         {/* Hiển thị Lương (UBI) */}
         <div style={{ marginTop: '10px', padding: '10px', background: '#e6f7ff', borderRadius: '6px', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontSize: '0.8rem', color: '#003366' }}>Mức UBI hiện tại ({currentUserInfo.ubiPercentage || 0}%):</span>
            <strong style={{ color: '#003366', fontSize: '1rem' }}>
                {((currentUserInfo.baseUBI || 0) * (currentUserInfo.ubiPercentage || 100) / 100).toLocaleString()} đ
            </strong>
         </div>
      </header>

      {/* Main Content */}
      <main style={{ flex: 1, padding: '15px', paddingBottom: '70px' }}>
        <Outlet />
      </main>

      {/* Bottom Navigation for Mobile / Tab Bar */}
      <nav style={{ 
        position: 'fixed', bottom: 0, left: 0, right: 0, background: 'white', 
        borderTop: '1px solid #ddd', display: 'flex', justifyContent: 'space-around', padding: '10px 0',
        boxShadow: '0 -2px 10px rgba(0,0,0,0.05)'
      }}>
        <Link to="/staff/my-tasks" style={linkStyle('/staff/my-tasks')}>
            <Icons.Task active={isActive('/staff/my-tasks')} />
            <span style={{ marginTop: '4px' }}>Nhiệm vụ</span>
        </Link>
        {/* Các tab khác của staff... */}
      </nav>
    </div>
  );
};

export default StaffLayout;
